import api from './api';

export const orderService = {
  createOrder: async (order) => (await api.post('/api/orders', order)).data,
  getAllOrders: async () => (await api.get('/api/orders')).data,
  getOrderById: async (id) => (await api.get(`/api/orders/${id}`)).data,
  getOrdersByUserId: async (userId) => (await api.get(`/api/orders/user/${userId}`)).data,
  updateOrder: async (id, order) => (await api.put(`/api/orders/${id}`, order)).data,
  deleteOrder: async (id) => (await api.delete(`/api/orders/${id}`)).data,
};
